		&lt;tr&gt;
			&lt;td&gt;B&lt;span style=&quot;line-height: 0; position: relative; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;1&lt;/span&gt;&amp;nbsp;(Thiamine)&lt;/td&gt;
			&lt;td&gt;Beri-beri&lt;/td&gt;
			&lt;td&gt;Liver, Peas, Yeast, etc.&amp;nbsp;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;B&lt;span style=&quot;line-height: 0; position: relative; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;2&lt;/span&gt;&amp;nbsp;(Riboflavin)&lt;/td&gt;
			&lt;td&gt;Retarded growth, bad skin&lt;/td&gt;
			&lt;td&gt;Fish, Meat, Eggs&lt;/td&gt;
