			&lt;td&gt;B&lt;span style=&quot;line-height: 0; position: relative; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;12&lt;/span&gt;&amp;nbsp;(Cyanocobalamin)&lt;/td&gt;
