			&lt;td&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;strong&gt;न्यूनता&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt; रोग&lt;/span&gt;&lt;/td&gt;
